export function IcoAIConfig() {
  const { palette } = useIlloStyle();
  // 8-tooth gear centered at 95,65, r=32 outer, r=22 inner
  const gear = () => {
    const cx = 95, cy = 65, ro = 32, ri = 22, teeth = 8;
    let d = '';
    for (let i = 0; i < teeth; i++) {
      const a0 = (i / teeth) * Math.PI * 2 - Math.PI / 2;
      const a1 = a0 + (0.3 / teeth) * Math.PI * 2;
      const a2 = a0 + (0.7 / teeth) * Math.PI * 2;
      const a3 = a0 + (1.0 / teeth) * Math.PI * 2;
      if (i === 0) d += `M ${cx + ri * Math.cos(a0)} ${cy + ri * Math.sin(a0)} `;
      d += `L ${cx + ro * Math.cos(a1)} ${cy + ro * Math.sin(a1)} `;
      d += `L ${cx + ro * Math.cos(a2)} ${cy + ro * Math.sin(a2)} `;
      d += `L ${cx + ri * Math.cos(a3)} ${cy + ri * Math.sin(a3)} `;
    }
    d += 'Z';
    return d;
  };
  return (
    <svg viewBox="0 0 200 130" preserveAspectRatio="xMidYMid slice" style={{ width: '100%', height: '100%' }}>
      <rect width="200" height="130" fill={palette.dark} />
      <path d={gear()} fill={palette.accent} />
      <circle cx="95" cy="65" r="12" fill={palette.dark} />
      {/* Sparkle dot upper-right */}
      <line x1="136" y1="24" x2="136" y2="38" stroke={palette.accent} strokeWidth="3" strokeLinecap="round" />
      <line x1="129" y1="31" x2="143" y2="31" stroke={palette.accent} strokeWidth="3" strokeLinecap="round" />
    </svg>
  );
}
